import { useState, useEffect } from "react";
import { useSelector } from "react-redux";
import { toast } from "react-toastify";
import { Link } from "react-router-dom";

function AdminPanel() {
  const user = useSelector((state) => state.auth.user);
  const [reports, setReports] = useState([]);

  useEffect(() => {
    if (user?.role === "admin") {
      fetch("http://localhost:3001/reports")
        .then((res) => res.json())
        .then((data) => setReports(Array.isArray(data) ? data : []))
        .catch((error) => {
          console.error("Reports fetch error:", error);
          toast.error("Ошибка загрузки отчетов");
        });
    }
  }, [user]);

  const handleGenerateReport = async () => {
    try {
      const reportData = {
        id: reports.length + 1,
        type: "files_summary",
        data: {
          files: await fetch("http://localhost:3001/files").then((res) => res.json()),
          generatedAt: new Date().toISOString(),
        },
      };
      const response = await fetch("http://localhost:3001/reports", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(reportData),
      });
      if (response.ok) {
        const newReport = await response.json();
        setReports([...reports, newReport]);
        toast.success("Отчет сгенерирован!");
      } else {
        toast.error("Не удалось сгенерировать отчет");
      }
    } catch (error) {
      console.error("Generate report error:", error);
      toast.error("Сетевая ошибка при генерации отчета");
    }
  };

  if (!user || user.role !== "admin") {
    return <div className="container mt-5"><h1>Доступ запрещен</h1></div>;
  }

  return (
    <div className="container mt-5">
      <h1 className="text-center mb-4">Панель администратора</h1>
      <div className="card shadow">
        <div className="card-body">
          <h2>Управление отчетами</h2>
          <button className="btn btn-primary mb-3" onClick={handleGenerateReport}>
            Сгенерировать отчет о файлах
          </button>
          <Link to="/reports" className="btn btn-primary mb-3 ms-2">
            Посмотреть подробные отчеты
          </Link>
          <h3>Список отчетов</h3>
          {reports.length === 0 ? (
            <p>Отчетов нет</p>
          ) : (
            <ul className="list-group">
              {reports.map((report) => (
                <li key={report.id} className="list-group-item">
                  Тип: {report.type}, Создан: {report.data.generatedAt}
                </li>
              ))}
            </ul>
          )}
          <h2 className="mt-4">Управление объявлениями</h2>
          <Link to="/announcements" className="btn btn-primary mb-3">
            Создать и просмотреть объявления
          </Link>
        </div>
      </div>
    </div>
  );
}

export default AdminPanel;
